import os, re, glob

files = sorted(glob.glob('/app/ocr/frame_*.txt'))

def get_prompts(text):
    lines = text.strip().split('\n')
    prompts = []
    for line in lines:
        stripped = line.strip()
        if stripped.startswith('>'):
            cmd = stripped[1:].strip()
            prompts.append(cmd)
    return prompts

def get_counter(text):
    m = re.search(r'Moves:\s*(\d+)', text)
    return int(m.group(1)) if m else None

def clean(cmd):
    cmd = cmd.strip()
    while cmd and cmd[-1] in '._':
        cmd = cmd[:-1]
    if cmd.startswith('D') and len(cmd) > 1 and cmd[1].islower():
        cmd = cmd[1:]
    return cmd

def norm(cmd):
    return clean(cmd).lower().replace(' ', '').replace(',', ',').strip()

def is_prefix(short, long):
    """Check if short is a prefix of long (allowing OCR noise)."""
    short = norm(short)
    long = norm(long)
    if not short:
        return True
    if not long:
        return False
    if short == long:
        return True
    # Allow trailing _ in short as wildcard
    short_base = short.rstrip('_')
    if long.startswith(short_base):
        return True
    # Check if long starts with most of short
    common = 0
    for i in range(min(len(short_base), len(long))):
        if short_base[i] == long[i]:
            common += 1
        else:
            break
    return common >= len(short_base) - 1 and common >= 2

frame_data = []
for f in files:
    text = open(f).read()
    prompts = get_prompts(text)
    counter = get_counter(text)
    frame_data.append({
        'file': os.path.basename(f),
        'prompts': prompts,
        'last': prompts[-1] if prompts else "",
        'counter': counter
    })

# Approach: track the LAST prompt across frames.
# When the last prompt grows (is an extension of previous), it's still being typed.
# When it changes to something new (not an extension), the previous was completed.
moves = []
current_cmd = frame_data[0]['last']  # The command being typed
prev_frame = frame_data[0]['file']

def is_typing_continuation(old, new):
    """Check if new is a continuation of old (same command being typed)."""
    old_clean = clean(old)
    new_clean = clean(new)
    if not old_clean:
        return False  # empty old means fresh prompt
    if not new_clean:
        return False  # empty new means fresh prompt (command completed)
    return is_prefix(old, new)

for fd in frame_data[1:]:
    new_last = fd['last']

    if is_typing_continuation(current_cmd, new_last):
        # Same command, possibly more typed
        current_cmd = new_last if len(new_last) > len(current_cmd) else current_cmd
    else:
        # Command changed - previous was completed
        completed = clean(current_cmd)
        if completed:
            moves.append(completed)
        current_cmd = new_last

    prev_frame = fd['file']

# Last command
completed = clean(current_cmd)
if completed:
    moves.append(completed)

# Deduplicate consecutive identical/very similar moves
deduped = []
for m in moves:
    if deduped and norm(m) == norm(deduped[-1]):
        if len(m) > len(deduped[-1]):
            deduped[-1] = m
        continue
    deduped.append(m)

for i, move in enumerate(deduped):
    print(f"{i+1}: {move!r}")

print(f"\nTotal moves: {len(deduped)}")
print(f"Raw moves: {len(moves)}")
counters = [(fd['file'], fd['counter']) for fd in frame_data if fd['counter'] is not None]
if counters:
    print(f"Last counter: {counters[-1]}")
PYEOF
cat /app/moves_v4.txt
